import{_ as o,c as t,o as r,ag as a}from"./chunks/framework.Bw-5EFTY.js";const p=JSON.parse('{"title":"DAG Worker Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-worker/SPEC.md","filePath":"packages/dag-worker/SPEC.md"}'),i={name:"packages/dag-worker/SPEC.md"};function c(s,e,n,d,l,u){return r(),t("div",null,e[0]||(e[0]=[a('<h1 id="dag-worker-specification" tabindex="-1">DAG Worker Specification <a class="header-anchor" href="#dag-worker-specification" aria-label="Permalink to &quot;DAG Worker Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Owns the dequeue-process loop for task execution within DAG runs. Applies lease acquisition, timeout enforcement, retry logic, dead letter queue (DLQ) handling, downstream task dispatch, and DAG run finalization behavior.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Depends on <code>dag-core</code> for domain contracts, state machines, port interfaces, and error builders.</li><li>Does not define DAG definitions, API contracts, or scheduling logic.</li><li>Does not own runtime orchestration (run creation, start) -- those belong to <code>dag-runtime</code>.</li><li>Does not own projection or observability concerns.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The package has three main modules:</p><ul><li><strong>WorkerLoopService</strong> (<code>services/worker-loop-service.ts</code>): The core processing loop. Each <code>processOnce()</code> call dequeues a message, acquires a lease, executes the task via <code>ITaskExecutorPort</code>, handles success/failure paths, dispatches downstream tasks, and finalizes the DAG run when all tasks are terminal.</li><li><strong>DownstreamTaskDispatcher</strong> (<code>services/downstream-task-dispatcher.ts</code>): Resolves downstream nodes, builds input payloads from edge bindings, creates task runs, and enqueues them.</li><li><strong>DagRunFinalizer</strong> (<code>services/dag-run-finalizer.ts</code>): Checks whether all tasks in a DAG run are terminal and determines success/failure outcome.</li><li><strong>DlqReinjectService</strong> (<code>services/dlq-reinject-service.ts</code>): Dequeues from the dead letter queue, transitions the task to retry state, and re-enqueues to the main queue.</li><li><strong>Composition factory</strong> (<code>composition/create-worker-loop-service.ts</code>): Wires <code>WorkerLoopService</code> from port dependencies and policy options.</li></ul><p>Supporting utility:</p><ul><li><code>replaceAttemptSegment(path, nextAttempt)</code> -- updates the attempt segment in an execution path array.</li></ul><h2 id="behavioral-contracts" tabindex="-1">Behavioral Contracts <a class="header-anchor" href="#behavioral-contracts" aria-label="Permalink to &quot;Behavioral Contracts&quot;">​</a></h2><h3 id="downstream-task-dispatch-atomicity" tabindex="-1">Downstream Task Dispatch Atomicity <a class="header-anchor" href="#downstream-task-dispatch-atomicity" aria-label="Permalink to &quot;Downstream Task Dispatch Atomicity&quot;">​</a></h3><p>When dispatching a downstream task, the create-then-enqueue sequence must be atomic in outcome:</p><ol><li>Create <code>TaskRun</code> record in storage with <code>queued</code> status.</li><li>Enqueue the task message to the queue.</li><li><strong>If enqueue fails</strong>: the <code>TaskRun</code> must be transitioned to <code>cancelled</code> status via the <code>CANCEL</code> event (<code>queued -&gt; cancelled</code>) to prevent orphaned records. A <code>TaskRun</code> in <code>queued</code> status with no corresponding queue message is an invariant violation. Note: the <code>queued -&gt; failed</code> transition does not exist in the state machine; <code>CANCEL</code> is the correct recovery path.</li></ol><p><strong>Current gap</strong>: The implementation creates the <code>TaskRun</code> then attempts enqueue. On enqueue failure, it returns an error but does not transition the orphaned <code>TaskRun</code>. This must be corrected.</p><h3 id="dlq-reinject-concurrency-safety" tabindex="-1">DLQ Reinject Concurrency Safety <a class="header-anchor" href="#dlq-reinject-concurrency-safety" aria-label="Permalink to &quot;DLQ Reinject Concurrency Safety&quot;">​</a></h3><p><code>DlqReinjectService.reinjectOnce</code> uses two layers of concurrency protection:</p><ol><li><strong>DLQ dequeue visibility timeout</strong>: only one worker receives a given DLQ message at a time.</li><li><strong>Lease acquisition</strong>: after dequeue, the service acquires a lease on the task run (<code>taskRun:{taskRunId}</code>) before modifying state. If the lease is held by another worker, the message is nacked and the method returns <code>reinjected: false</code> without error.</li></ol><p>The lease is always released in a <code>finally</code> block after processing completes.</p><h3 id="dag-run-finalization-classification" tabindex="-1">DAG Run Finalization Classification <a class="header-anchor" href="#dag-run-finalization-classification" aria-label="Permalink to &quot;DAG Run Finalization Classification&quot;">​</a></h3><p><code>DagRunFinalizer</code> determines the outcome of a DAG run when all tasks reach terminal states. The classification rules are:</p><ul><li><strong>Terminal task states</strong>: <code>success</code>, <code>failed</code>, <code>upstream_failed</code>, <code>skipped</code>, <code>cancelled</code></li><li><strong>Non-terminal (pending) states</strong>: <code>created</code>, <code>queued</code>, <code>running</code></li><li><strong>Failure-contributing states</strong>: <code>failed</code> only</li><li><strong>Non-failure terminal states</strong>: <code>success</code>, <code>upstream_failed</code>, <code>skipped</code>, <code>cancelled</code></li></ul><p>A DAG run is <code>success</code> when all tasks are terminal and <strong>none</strong> are in the <code>failed</code> state. <code>upstream_failed</code>, <code>skipped</code>, and <code>cancelled</code> tasks do not indicate DAG-level failure — they represent expected propagation of upstream failures, conditional skips, or user cancellation.</p><p><strong>Current gap</strong>: The <code>FAILURE_TASK_STATUSES</code> set includes <code>upstream_failed</code> and <code>cancelled</code>, causing DAG runs to be marked <code>failed</code> when tasks are only <code>upstream_failed</code>/<code>cancelled</code> (no actual <code>failed</code> task). Additionally, <code>skipped</code> is not in either the pending or failure set, which may cause incorrect finalization. This must be corrected.</p><h3 id="lease-failure-handling" tabindex="-1">Lease Failure Handling <a class="header-anchor" href="#lease-failure-handling" aria-label="Permalink to &quot;Lease Failure Handling&quot;">​</a></h3><p>When <code>WorkerLoopService</code> fails to acquire a lease (another worker already holds it), this is a normal contention scenario, not an error. The method should return a non-error result indicating no work was processed (<code>processed: false</code>), allowing the message to remain in the queue for the lease holder to process.</p><h3 id="timeout-enforcement-scope" tabindex="-1">Timeout Enforcement Scope <a class="header-anchor" href="#timeout-enforcement-scope" aria-label="Permalink to &quot;Timeout Enforcement Scope&quot;">​</a></h3><p>Task timeout (<code>defaultTimeoutMs</code>) is enforced via <code>AbortController</code> signal during execution. However, if the executor does not respect the abort signal, the timeout has no effect. This is a known limitation — node implementations must cooperate with the abort signal for timeout to be effective.</p><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is SSOT for:</p><ul><li><code>IWorkerLoopOptions</code> -- worker configuration (workerId, leaseDurationMs, visibilityTimeoutMs, retryEnabled, deadLetterEnabled, maxAttempts, defaultTimeoutMs)</li><li><code>IWorkerLoopResult</code> -- processing result (processed, taskRunId, retried)</li><li><code>IDlqReinjectResult</code> -- reinject result (reinjected, taskRunId)</li><li><code>IWorkerLoopDependencies</code> -- dependency injection shape for the composition factory</li><li><code>IWorkerLoopPolicyOptions</code> -- policy-level options with optional retry/DLQ flags</li></ul><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><ul><li><code>WorkerLoopService</code> -- main service class <ul><li><code>processOnce(): Promise&lt;TResult&lt;IWorkerLoopResult, IDagError&gt;&gt;</code> -- dequeue and process one task</li></ul></li><li><code>DlqReinjectService</code> -- DLQ reinject service <ul><li><code>reinjectOnce(workerId, visibilityTimeoutMs): Promise&lt;TResult&lt;IDlqReinjectResult, IDagError&gt;&gt;</code></li></ul></li><li><code>createWorkerLoopService(deps, options): WorkerLoopService</code> -- composition factory</li><li><code>replaceAttemptSegment(path, nextAttempt): string[]</code> -- execution path utility</li></ul><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li><code>ITaskExecutorPort</code> (from <code>dag-core</code>) -- consumers implement this to define how tasks are executed.</li><li><code>ILeasePort</code> (from <code>dag-core</code>) -- consumers provide lease acquisition/release mechanics.</li><li><code>IQueuePort</code> (from <code>dag-core</code>) -- consumers provide queue enqueue/dequeue/ack/nack behavior.</li><li><code>IRunProgressEventReporter</code> (from <code>dag-core</code>) -- optional reporter for publishing task/run progress events.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>All errors use <code>IDagError</code> from <code>dag-core</code> with the following codes:</p><p><strong>Lease errors</strong> (<code>category: &#39;lease&#39;</code>):</p><ul><li><code>DAG_LEASE_CONTRACT_VIOLATION</code> -- failed to acquire lease for a task run</li></ul><p><strong>Validation errors</strong> (<code>category: &#39;validation&#39;</code>):</p><ul><li><code>DAG_VALIDATION_TASK_RUN_NOT_FOUND</code> -- task run missing for dequeued message</li><li><code>DAG_VALIDATION_DAG_RUN_NOT_FOUND</code> -- DAG run missing</li><li><code>DAG_VALIDATION_NODE_NOT_FOUND</code> -- node definition missing for task</li><li><code>DAG_VALIDATION_DEFINITION_SNAPSHOT_MISSING</code> / <code>_INVALID</code> / <code>_PARSE_FAILED</code> -- snapshot errors</li><li><code>DAG_VALIDATION_DOWNSTREAM_NODE_NOT_FOUND</code> -- downstream node missing</li><li><code>DAG_VALIDATION_BINDING_*</code> -- binding resolution errors (REQUIRED, OUTPUT_KEY_MISSING, INPUT_KEY_MISSING, INPUT_KEY_CONFLICT, LIST_PAYLOAD_INVALID)</li><li><code>DAG_VALIDATION_UPSTREAM_OUTPUT_*</code> -- upstream output errors (MISSING, INVALID, PARSE_FAILED)</li><li><code>DAG_VALIDATION_DEAD_LETTER_QUEUE_NOT_CONFIGURED</code> -- DLQ enabled but not configured</li></ul><p><strong>Dispatch errors</strong> (<code>category: &#39;dispatch&#39;</code>):</p><ul><li><code>DAG_DISPATCH_ENQUEUE_RETRY_FAILED</code> -- retry enqueue failure</li><li><code>DAG_DISPATCH_ENQUEUE_DOWNSTREAM_FAILED</code> -- downstream enqueue failure</li><li><code>DAG_DISPATCH_DEAD_LETTER_ENQUEUE_FAILED</code> -- DLQ enqueue failure</li><li><code>DAG_DISPATCH_REINJECT_ENQUEUE_FAILED</code> -- reinject enqueue failure</li></ul><p><strong>Task execution errors</strong> (<code>category: &#39;task_execution&#39;</code>):</p><ul><li><code>DAG_TASK_EXECUTION_TIMEOUT</code> -- task exceeded timeout</li><li><code>DAG_TASK_EXECUTION_EXCEPTION</code> -- executor threw an exception</li><li><code>DAG_TASK_EXECUTION_FAILED</code> -- generic run failure</li></ul><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><p>No classes in this package use the <code>implements</code> keyword. All port dependencies are consumed via constructor injection.</p><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><p>None. Service classes are standalone (no <code>extends</code>).</p><h3 id="port-consumption-via-di" tabindex="-1">Port Consumption via DI <a class="header-anchor" href="#port-consumption-via-di" aria-label="Permalink to &quot;Port Consumption via DI&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service Class</th><th>Injected Port (from dag-core)</th><th>Location</th></tr></thead><tbody><tr><td><code>WorkerLoopService</code></td><td><code>IStoragePort</code>, <code>IQueuePort</code>, <code>ILeasePort</code>, <code>ITaskExecutorPort</code>, <code>IClockPort</code></td><td><code>src/services/worker-loop-service.ts</code></td></tr><tr><td><code>DlqReinjectService</code></td><td><code>IStoragePort</code>, <code>IQueuePort</code> (x2), <code>ILeasePort</code>, <code>IClockPort</code></td><td><code>src/services/dlq-reinject-service.ts</code></td></tr></tbody></table><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Consumer Class</th><th>Location</th></tr></thead><tbody><tr><td><code>IStoragePort</code> (dag-core)</td><td><code>WorkerLoopService</code>, <code>DlqReinjectService</code></td><td><code>src/services/</code></td></tr><tr><td><code>IQueuePort</code> (dag-core)</td><td><code>WorkerLoopService</code>, <code>DlqReinjectService</code></td><td><code>src/services/</code></td></tr><tr><td><code>ILeasePort</code> (dag-core)</td><td><code>WorkerLoopService</code>, <code>DlqReinjectService</code></td><td><code>src/services/</code></td></tr><tr><td><code>ITaskExecutorPort</code> (dag-core)</td><td><code>WorkerLoopService</code></td><td><code>src/services/worker-loop-service.ts</code></td></tr><tr><td><code>IClockPort</code> (dag-core)</td><td><code>WorkerLoopService</code>, <code>DlqReinjectService</code></td><td><code>src/services/</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li><strong>Unit tests</strong>: <code>worker-loop-service.test.ts</code>, <code>dlq-reinject-service.test.ts</code>, <code>worker-loop-composition.test.ts</code></li><li>Tests use in-memory port implementations from <code>dag-core</code>.</li><li>Coverage focus: lease acquisition/release, success/failure paths, retry logic with attempt increment, DLQ enqueue/reinject, downstream dispatch with binding resolution, DAG run finalization (success/failure), timeout enforcement.</li><li>Run: <code>pnpm --filter @robota-sdk/dag-worker test</code></li></ul>',56)]))}const m=o(i,[["render",c]]);export{p as __pageData,m as default};
